import{_ as e,o as d,c as a,ae as o}from"./chunks/framework.CylwKCfq.js";const g=JSON.parse('{"title":"Components","description":"","frontmatter":{},"headers":[],"relativePath":"api/components.md","filePath":"api/components.md"}'),r={name:"api/components.md"};function n(s,t,i,l,h,c){return d(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h1><h2 id="graphexplorer" tabindex="-1"><code>GraphExplorer</code> <a class="header-anchor" href="#graphexplorer" aria-label="Permalink to &quot;`GraphExplorer`&quot;">​</a></h2><p>ReactFlow-based interactive graph renderer. Best for small-to-medium graphs (up to ~500 nodes).</p><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { GraphExplorer } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@trustin/txgraph&#39;</span></span></code></pre></div><h3 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Prop</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>nodes</code></td><td><code>TxNode[]</code></td><td>required</td><td>Array of graph nodes</td></tr><tr><td><code>edges</code></td><td><code>TxEdge[]</code></td><td>required</td><td>Array of graph edges</td></tr><tr><td><code>stats</code></td><td><code>TxGraphStats</code></td><td>—</td><td>Optional stats (shown in panel)</td></tr><tr><td><code>loading</code></td><td><code>boolean</code></td><td><code>false</code></td><td>Show full-screen loading overlay</td></tr><tr><td><code>expandingNode</code></td><td><code>string | null</code></td><td><code>null</code></td><td>Address of node currently being expanded (shows spinner)</td></tr><tr><td><code>selectedAddress</code></td><td><code>string | null</code></td><td><code>null</code></td><td>Highlight the path from root to this address</td></tr><tr><td><code>onNodeSelect</code></td><td><code>(node: TxNode | null) =&gt; void</code></td><td>—</td><td>Called when user clicks a node (or background)</td></tr><tr><td><code>onNodeExpand</code></td><td><code>(address: string) =&gt; void</code></td><td>—</td><td>Called when user clicks the <strong>+</strong> expand button</td></tr><tr><td><code>onNodeDelete</code></td><td><code>(address: string) =&gt; void</code></td><td>—</td><td>Called when user clicks the <strong>✕</strong> delete button</td></tr></tbody></table><h3 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h3><p>The graph uses <strong>Dagre</strong> for automatic left-to-right hierarchical layout. Nodes are arranged by transaction depth. Layout is recomputed whenever <code>nodes</code> or <code>edges</code> change.</p><h3 id="selection-path-highlighting" tabindex="-1">Selection &amp; Path Highlighting <a class="header-anchor" href="#selection-path-highlighting" aria-label="Permalink to &quot;Selection &amp; Path Highlighting&quot;">​</a></h3><p>When <code>selectedAddress</code> is set, the component:</p><ol><li>Finds all paths from the root node to the selected address (DFS with backtracking)</li><li>Highlights nodes and edges on any path</li><li>Dims all other nodes and edges (opacity 0.25)</li></ol><h3 id="node-appearance" tabindex="-1">Node Appearance <a class="header-anchor" href="#node-appearance" aria-label="Permalink to &quot;Node Appearance&quot;">​</a></h3><table tabindex="0"><thead><tr><th>State</th><th>Visual</th></tr></thead><tbody><tr><td>Root node</td><td>Blue border + glow</td></tr><tr><td>High risk</td><td>Red border + red background</td></tr><tr><td>Medium risk</td><td>Yellow border + yellow background</td></tr><tr><td>Low risk</td><td>Green border + green background</td></tr><tr><td>Unknown risk</td><td>Gray border</td></tr><tr><td>Stopped node</td><td>Dashed border + warning icon</td></tr><tr><td>Selected</td><td>Blue glow ring</td></tr><tr><td>Dimmed (not on path)</td><td>25% opacity</td></tr><tr><td>Expanding</td><td>Spinner overlay</td></tr></tbody></table><hr><h2 id="graphexplorersigma" tabindex="-1"><code>GraphExplorerSigma</code> <a class="header-anchor" href="#graphexplorersigma" aria-label="Permalink to &quot;`GraphExplorerSigma`&quot;">​</a></h2><p>Sigma.js + WebGL-based renderer. Best for large graphs (500+ nodes). Uses canvas for labels, WebGL for nodes/edges.</p><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { GraphExplorerSigma } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@trustin/txgraph&#39;</span></span></code></pre></div><h3 id="props-1" tabindex="-1">Props <a class="header-anchor" href="#props-1" aria-label="Permalink to &quot;Props&quot;">​</a></h3><p>Same props as <code>GraphExplorer</code> — both components implement <code>GraphExplorerProps</code>.</p><h3 id="interactions" tabindex="-1">Interactions <a class="header-anchor" href="#interactions" aria-label="Permalink to &quot;Interactions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Action</th><th>Result</th></tr></thead><tbody><tr><td>Click node</td><td><code>onNodeSelect(node)</code></td></tr><tr><td>Click background</td><td><code>onNodeSelect(null)</code></td></tr><tr><td>Double-click node</td><td><code>onNodeExpand(address)</code></td></tr><tr><td>Right-click node</td><td><code>onNodeDelete(address)</code></td></tr><tr><td>Scroll</td><td>Zoom in/out</td></tr><tr><td>Drag</td><td>Pan</td></tr></tbody></table><h3 id="built-in-controls" tabindex="-1">Built-in Controls <a class="header-anchor" href="#built-in-controls" aria-label="Permalink to &quot;Built-in Controls&quot;">​</a></h3><p>The Sigma renderer includes floating controls:</p><ul><li><strong>+</strong> / <strong>−</strong> — Zoom in/out</li><li><strong>⊡</strong> — Fit all nodes in view</li></ul><h3 id="layout-1" tabindex="-1">Layout <a class="header-anchor" href="#layout-1" aria-label="Permalink to &quot;Layout&quot;">​</a></h3><p>Uses a custom depth-based left-to-right layout:</p><ul><li>X position = <code>depth × 3.5</code> (graph coordinates)</li><li>Y position = evenly spaced within each depth level</li><li>No overlap guaranteed</li></ul><h3 id="camera" tabindex="-1">Camera <a class="header-anchor" href="#camera" aria-label="Permalink to &quot;Camera&quot;">​</a></h3><p>On mount, the camera auto-fits to show all nodes at a comfortable ~38px radius. The camera ratio adapts to graph size.</p>',29)])])}const u=e(r,[["render",n]]);export{g as __pageData,u as default};
